// ─── LOOKUP HELPERS ──────────────────────────────────────────────────────────

/**
 * Search by exact code (case-insensitive, space-normalized).
 */
export function findByCode(code: string): LamitakProduct[] {
  const q = code.toUpperCase().replace(/\s+/g, ' ').trim();
  return LAMITAK_PRODUCTS.filter(
    (p) => p.code.toUpperCase().replace(/\s+/g, ' ').trim() === q
  );
}

/**
 * Search by code prefix — e.g. "ATP" returns all ATP items.
 */
export function findByPrefix(prefix: string): LamitakProduct[] {
  const q = prefix.toUpperCase().replace(/\s+/g, ' ').trim();
  return LAMITAK_PRODUCTS.filter((p) =>
    p.code.toUpperCase().replace(/\s+/g, ' ').trim().startsWith(q)
  );
}

/**
 * Full-text search across code, itemName, and designName.
 */
export function searchProducts(query: string): LamitakProduct[] {
  const q = query.toUpperCase().replace(/\s+/g, ' ').trim();
  return LAMITAK_PRODUCTS.filter(
    (p) =>
      p.code.toUpperCase().includes(q) ||
      p.itemName.toUpperCase().includes(q) ||
      p.designName.toUpperCase().includes(q)
  );
}

/**
 * Format price for display.
 */
export function formatProductPrice(price: number): string {
  return `Rp ${price.toLocaleString('id-ID')}`;
}

/**
 * Format a product result in the standard VIA display format.
 * Example:
 *   Item: ATP 1358M - LAMITAK HPL 4'x8' | MARMO CLASSICO PRO
 *   Code: ATP 1358M
 *   Design Name: MARMO CLASSICO PRO
 *   Price: Rp 2.331.000 incl. Tax
 */
export function formatProductResult(p: LamitakProduct): string {
  return [
    `Item: ${p.itemName}`,
    `Code: ${p.code}`,
    `Design Name: ${p.designName}`,
    `Price: ${formatProductPrice(p.rateInclTax)} incl. Tax`,
  ].join('\n');
}

export const LAMITAK_CATALOG_META = {
  totalItems: 800,
  effectiveDate: 'July 2025',
  currency: 'IDR',
  taxRate: 11,
  source: 'Zoho Books — lamitak-products.csv',
};

/**
 * Fuzzy search — matches by code (exact, prefix, partial) OR design name.
 * Priority: exact code > code starts-with > code contains > design name contains
 * e.g. "ATP 1358" matches "ATP 1358M"; "STOFFA MOCCA" matches by design name
 */
export function fuzzyFindByCode(query: string): LamitakProduct[] {
  const q = query.toUpperCase().replace(/\s+/g, ' ').trim();

  // 1. Exact code match
  const exact = LAMITAK_PRODUCTS.filter(
    (p) => p.code.toUpperCase().replace(/\s+/g, ' ').trim() === q
  );
  if (exact.length > 0) return exact;

  // 2. Catalog code starts with query (e.g. "ATP 1358" → "ATP 1358M")
  const startsWith = LAMITAK_PRODUCTS.filter((p) =>
    p.code.toUpperCase().replace(/\s+/g, ' ').trim().startsWith(q)
  );
  if (startsWith.length > 0) return startsWith;

  // 3. Query starts with catalog code (prefix group, e.g. "ATP" → all ATP items)
  const prefixGroup = LAMITAK_PRODUCTS.filter((p) =>
    q.startsWith(p.code.toUpperCase().replace(/\s+/g, ' ').trim() + ' ') ||
    q === p.code.toUpperCase().replace(/\s+/g, ' ').trim()
  );
  if (prefixGroup.length > 0) return prefixGroup;

  // 4. Code contains query
  const codeContains = LAMITAK_PRODUCTS.filter((p) =>
    p.code.toUpperCase().replace(/\s+/g, ' ').includes(q)
  );
  if (codeContains.length > 0) return codeContains;

  // 5. Design name exact match
  const designExact = LAMITAK_PRODUCTS.filter(
    (p) => p.designName.toUpperCase().trim() === q
  );
  if (designExact.length > 0) return designExact;

  // 6. Design name contains all query words (e.g. "STOFFA MOCCA" matches "STOFFA MOCA" loosely)
  const words = q.split(' ').filter((w) => w.length >= 3);
  if (words.length > 0) {
    const designWords = LAMITAK_PRODUCTS.filter((p) =>
      words.every((w) => p.designName.toUpperCase().includes(w))
    );
    if (designWords.length > 0) return designWords;

    // 7. Design name contains ANY query word (broader fallback)
    const designAny = LAMITAK_PRODUCTS.filter((p) =>
      words.some((w) => w.length >= 4 && p.designName.toUpperCase().includes(w))
    );
    if (designAny.length > 0) return designAny;
  }

  return [];
}
